def is_password_insecure(password: str) -> bool:
    pwd = (password or "").strip()
    if not pwd:
        return True
    lowered = pwd.lower()
    if lowered in _COMMON_PASSWORDS:
        return True
    # Block very repetitive passwords like "aaaaaaaa", "11111111"
    if re.fullmatch(r"(.)\1{7,}", pwd):
        return True

